import json, re

# ═══ TEBAKGAMBAR - verifikasi pola URL level/nomor ═══
with open('src/data/tebakgambar.json') as f: data = json.load(f)
print(f'=== TEBAKGAMBAR: {len(data)} item ===')

# Cek duplikat URL
from collections import Counter
urls = [d['img'] for d in data]
dup_urls = {u: c for u, c in Counter(urls).items() if c > 1}
if dup_urls:
    print(f'URL DUPLIKAT: {len(dup_urls)} URL dipakai lebih dari 1x')
    for u, c in list(dup_urls.items())[:5]:
        items = [d['jawaban'] for d in data if d['img'] == u]
        print(f'  {items} -> {u}')
else:
    print('Tidak ada URL duplikat')

# Cek duplikat jawaban
jawabans = [d['jawaban'] for d in data]
dup_j = {j: c for j, c in Counter(jawabans).items() if c > 1}
if dup_j:
    print(f'JAWABAN DUPLIKAT ({len(dup_j)}): {list(dup_j.items())[:10]}')
else:
    print('Tidak ada jawaban duplikat')

# Cek urutan level vs nomor (apakah berurutan atau ada lompatan)
levels = {}
for d in data:
    m = re.search(r'level-(\d+)-nomor-(\d+)', d['img'])
    if m:
        lv, no = int(m.group(1)), int(m.group(2))
        if lv not in levels: levels[lv] = []
        levels[lv].append(no)

print(f'Level range: {min(levels)} - {max(levels)}')
for lv in sorted(levels.keys()):
    nos = sorted(levels[lv])
    expected = list(range(1, len(nos)+1))
    if nos != expected:
        print(f'  Level {lv}: nomor tidak berurutan! {nos[:5]}...')
    else:
        print(f'  Level {lv}: {len(nos)} soal (nomor 1-{nos[-1]}) ✓')
